func checkEmailAge(emails [3]email) [3]bool {
	isOldChan := make(chan bool)

	sendIsOld(isOldChan, emails)

	isOld := [3]bool{}
	isOld[0] = <-isOldChan
	isOld[1] = <-isOldChan
	isOld[2] = <-isOldChan
	return isOld
}

